import React, { useState, useEffect } from "react";

// Screens
import SplashScreen from "./screens/SplashScreen.jsx";
import SignInScreen from "./screens/SignInScreen.jsx";
import SignUpScreen from "./screens/SignUpScreen.jsx";
import HomeScreen from "./screens/HomeScreen.jsx";
import GoalsScreen from "./screens/GoalsScreen.jsx";
import LoansScreen from "./screens/LoansScreen.jsx";
import ProfileScreen from "./screens/ProfileScreen.jsx";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen.jsx";
import DepositScreen from "./screens/DepositScreen.jsx";
import WithdrawScreen from "./screens/WithdrawScreen.jsx";
import SavingsDepositScreen from "./screens/SavingsDepositScreen.jsx";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen.jsx";

// Icons
import { Home, Target, CreditCard, User } from "lucide-react";

// Toast component
function Toast({ message, type, onClose }) {
  if (!message) return null;
  return (
    <div
      className={`fixed top-6 right-6 px-4 py-3 rounded-lg shadow-lg text-white ${
        type === "success" ? "bg-emerald-600" : "bg-red-600"
      } animate-fade-in`}
    >
      <span>{message}</span>
      <button className="ml-4 font-bold" onClick={onClose}>
        ✕
      </button>
    </div>
  );
}

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [tab, setTab] = useState("Home");

  // Toast
  const [toast, setToast] = useState({ message: "", type: "success" });
  const showToast = (message, type = "success") => {
    setToast({ message, type });
    setTimeout(() => setToast({ message: "", type }), 3000);
  };

  // Mock user & data
  const [user] = useState({
    name: "Faith Bode",
    email: "faith@example.com",
    joinedDate: "Jan 2025",
  });
  const [balance, setBalance] = useState(1500);
  const [savingsBalance, setSavingsBalance] = useState(300);
  const [goals] = useState([
    { id: 1, title: "Buy PS5", description: "Save for PS5 console", amountSaved: 100, targetAmount: 500 },
  ]);
  const [loans] = useState([]);
  const [transactions, setTransactions] = useState([]);

  // Splash → SignIn
  useEffect(() => {
    const timer = setTimeout(() => setCurrentScreen("SignIn"), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Transaction handlers
  const handleDeposit = (amount) => {
    setBalance((prev) => prev + amount);
    setTransactions((prev) => [
      { id: Date.now(), type: "deposit", title: "Deposit", amount, date: new Date().toLocaleDateString() },
      ...prev,
    ]);
    showToast(`Successfully deposited $${amount}`, "success");
    setCurrentScreen("Dashboard");
  };

  const handleWithdraw = (amount) => {
    if (amount > balance) {
      showToast("Insufficient balance", "error");
      return;
    }
    setBalance((prev) => prev - amount);
    setTransactions((prev) => [
      { id: Date.now(), type: "withdraw", title: "Withdrawal", amount, date: new Date().toLocaleDateString() },
      ...prev,
    ]);
    showToast(`Successfully withdrew $${amount}`, "success");
    setCurrentScreen("Dashboard");
  };

  const handleSavingsDeposit = (amount) => {
    if (amount > balance) {
      showToast("Insufficient balance for savings", "error");
      return;
    }
    setBalance((prev) => prev - amount);
    setSavingsBalance((prev) => prev + amount);
    setTransactions((prev) => [
      { id: Date.now(), type: "savings", title: "Savings Deposit", amount, date: new Date().toLocaleDateString() },
      ...prev,
    ]);
    showToast(`Successfully deposited $${amount} into savings`, "success");
    setCurrentScreen("Dashboard");
  };

  const handleSavingsWithdraw = (amount) => {
    if (amount > savingsBalance) {
      showToast("Insufficient savings balance", "error");
      return;
    }
    setSavingsBalance((prev) => prev - amount);
    setBalance((prev) => prev + amount);
    setTransactions((prev) => [
      { id: Date.now(), type: "withdraw-savings", title: "Savings Withdrawal", amount, date: new Date().toLocaleDateString() },
      ...prev,
    ]);
    showToast(`Successfully withdrew $${amount} from savings`, "success");
    setCurrentScreen("Dashboard");
  };

  // Screen rendering
  const renderScreen = () => {
    switch (currentScreen) {
      case "Splash":
        return <SplashScreen onFinish={() => setCurrentScreen("SignIn")} />;
      case "SignIn":
        return <SignInScreen onSignIn={() => setCurrentScreen("Dashboard")} />;
      case "SignUp":
        return <SignUpScreen onSignUp={() => setCurrentScreen("Dashboard")} />;
      case "Deposit":
        return <DepositScreen onDeposit={handleDeposit} setCurrentScreen={setCurrentScreen} showToast={showToast} />;
      case "Withdraw":
        return <WithdrawScreen balance={balance} onWithdraw={handleWithdraw} setCurrentScreen={setCurrentScreen} showToast={showToast} />;
      case "SavingsDeposit":
        return <SavingsDepositScreen savingsBalance={savingsBalance} onDeposit={handleSavingsDeposit} setCurrentScreen={setCurrentScreen} showToast={showToast} />;
      case "SavingsWithdraw":
        return <SavingsWithdrawScreen savingsBalance={savingsBalance} onWithdraw={handleSavingsWithdraw} setCurrentScreen={setCurrentScreen} showToast={showToast} />;
      case "Transactions":
        return <TransactionHistoryScreen transactions={transactions} />;
      case "Dashboard":
      default:
        switch (tab) {
          case "Home":
            return <HomeScreen balance={balance} savingsBalance={savingsBalance} transactions={transactions} userName={user.name} openScreen={setCurrentScreen} />;
          case "Goals":
            return <GoalsScreen goals={goals} />;
          case "Loans":
            return <LoansScreen loans={loans} />;
          case "Profile":
            return <ProfileScreen user={user} />;
          default:
            return null;
        }
    }
  };

  const tabs = [
    { key: "Home", label: "Home", icon: Home },
    { key: "Goals", label: "Goals", icon: Target },
    { key: "Loans", label: "Loans", icon: CreditCard },
    { key: "Profile", label: "Profile", icon: User },
  ];

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      {renderScreen()}

      {currentScreen === "Dashboard" && (
        <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-gray-200 flex">
          {tabs.map((t) => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={`flex-1 py-3 flex flex-col items-center ${tab === t.key ? "text-teal-600" : "text-gray-400"}`}
            >
              <t.icon size={22} />
              <span className="text-xs mt-1">{t.label}</span>
            </button>
          ))}
        </nav>
      )}

      {/* Toast notifications */}
      <Toast message={toast.message} type={toast.type} onClose={() => setToast({ message: "", type: "success" })} />
    </div>
  );
}
